/**
 * @suppress
 */
public object FfiConverterTypeFlareNode: FfiConverter<FlareNode, Pointer> {

    override fun lower(value: FlareNode): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): FlareNode {
        return FlareNode(value)
    }

    override fun read(buf: ByteBuffer): FlareNode {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: FlareNode) = 8UL

    override fun write(value: FlareNode, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



