/**
 * Error type exposed to mobile platforms via UniFFI.
 */
sealed class FlareException: kotlin.Exception() {
    
    class CryptoException(
        
        val `msg`: kotlin.String
        ) : FlareException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class StorageException(
        
        val `msg`: kotlin.String
        ) : FlareException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class RoutingException(
        
        val `msg`: kotlin.String
        ) : FlareException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class SerializationException(
        
        val `msg`: kotlin.String
        ) : FlareException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class InvalidInput(
        
        val `msg`: kotlin.String
        ) : FlareException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<FlareException> {
        override fun lift(error_buf: RustBuffer.ByValue): FlareException = FfiConverterTypeFlareError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeFlareError : FfiConverterRustBuffer<FlareException> {
    override fun read(buf: ByteBuffer): FlareException {
        

        return when(buf.getInt()) {
            1 -> FlareException.CryptoException(
                FfiConverterString.read(buf),
                )
            2 -> FlareException.StorageException(
                FfiConverterString.read(buf),
                )
            3 -> FlareException.RoutingException(
                FfiConverterString.read(buf),
                )
            4 -> FlareException.SerializationException(
                FfiConverterString.read(buf),
                )
            5 -> FlareException.InvalidInput(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FlareException): ULong {
        return when(value) {
            is FlareException.CryptoException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is FlareException.StorageException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is FlareException.RoutingException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is FlareException.SerializationException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is FlareException.InvalidInput -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
        }
    }

    override fun write(value: FlareException, buf: ByteBuffer) {
        when(value) {
            is FlareException.CryptoException -> {
                buf.putInt(1)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is FlareException.StorageException -> {
                buf.putInt(2)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is FlareException.RoutingException -> {
                buf.putInt(3)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is FlareException.SerializationException -> {
                buf.putInt(4)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is FlareException.InvalidInput -> {
                buf.putInt(5)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalString: FfiConverterRustBuffer<kotlin.String?> {
    override fun read(buf: ByteBuffer): kotlin.String? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterString.read(buf)
    }

    override fun allocationSize(value: kotlin.String?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterString.allocationSize(value)
        }
    }

    override fun write(value: kotlin.String?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterString.write(value, buf)
